SELECT location, condition
FROM organs
WHERE installation_year >= strftime('%Y', 'now') - 10;

SELECT builder, condition
FROM organs
WHERE construction_year > 1900;

SELECT restoration_id, description
FROM restorations
WHERE status = 'In Progress';

SELECT COUNT(*) 
FROM organs 
WHERE condition = 'Excellent';

SELECT condition, COUNT(*) as organ_count
FROM organs
GROUP BY condition;

SELECT organ_id, COUNT(*) AS view_count
FROM public_views
GROUP BY organ_id;

SELECT COUNT(*) AS total_views
FROM public_views
WHERE organ_id = 1;

SELECT organ_id, builder, construction_year
FROM organs
ORDER BY construction_year DESC;
